import axios from 'axios'
import authHeader from './auth-header'

const API_URL = process.env.VUE_APP_API_URL || 'http://localhost:8080/api'

/**
 * 获取当前用户信息
 * @returns {Promise} 返回用户详细信息
 */
export const getCurrentUser = () => {
  return axios.get(`${API_URL}/user/me`, { headers: authHeader() })
}

/**
 * 更新用户个人资料
 * @param {Object} userData 用户数据对象，包含需要更新的字段
 * @returns {Promise} 返回更新结果
 */
export const updateUserProfile = (userData) => {
  return axios.put(`${API_URL}/user/profile`, userData, { headers: authHeader() })
}

/**
 * 修改用户密码
 * @param {String} oldPassword 旧密码
 * @param {String} newPassword 新密码
 * @returns {Promise} 返回修改结果
 */
export const changePassword = (oldPassword, newPassword) => {
  return axios.post(
    `${API_URL}/user/change-password`,
    { oldPassword, newPassword },
    { headers: authHeader() }
  )
}

/**
 * 获取用户统计信息
 * @returns {Promise} 返回用户统计数据
 */
export const getUserStats = () => {
  return axios.get(`${API_URL}/user/stats`, { headers: authHeader() })
}

/**
 * 上传用户头像
 * @param {FormData} formData 包含头像文件的FormData
 * @returns {Promise} 返回上传结果
 */
export const uploadAvatar = (formData) => {
  return axios.post(`${API_URL}/user/avatar`, formData, {
    headers: {
      ...authHeader(),
      'Content-Type': 'multipart/form-data'
    }
  })
}

/**
 * 删除用户账户
 * @param {String} password 用户密码（确认身份）
 * @returns {Promise} 返回删除结果
 */
export const deleteAccount = (password) => {
  return axios.post(
    `${API_URL}/user/delete-account`,
    { password },
    { headers: authHeader() }
  )
}
